sql:
SELECT recipe_name, ratings
FROM recipes
ORDER BY ratings DESC;

external_knowledge:
- Popularity is determined by user interactions, ratings, and comments; 
- User interactions include activities such as views, likes, and saves; 
- Nutritional information includes calories, protein, fat, and carbohydrates per serving.

; Top-rated recipes refer to those with the highest average ratings given by users; 
; User engagement can be measured by the number of views and saves a recipe receives;
; Nutritional value is determined by the total calories, protein, fat, and carbohydrates per serving.

sql:
SELECT username, email
FROM users
WHERE user_id IN (
  SELECT created_by
  FROM recipes
);
